1	import { useCallback } from 'react';
2	import {
3	  ActivityIndicator,
4	  Pressable,
5	  type PressableProps,
6	  type StyleProp,
7	  StyleSheet,
8	  Text,
9	  type ViewStyle,
10	} from 'react-native';
11	import Animated, {
12	  useAnimatedStyle,
13	  useSharedValue,
14	  withSpring,
15	  type WithSpringConfig,
16	} from 'react-native-reanimated';
17	import * as Haptics from 'expo-haptics';
18	import { colors, radii, shadows, spacing } from '@/design/tokens';
19	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
20	import { useReducedMotion } from '@/design/useReducedMotion';
21	import { textStyles } from '@/design/typography';
22	
23	type Variant = 'primary' | 'secondary';
24	
25	export type ButtonProps = {
26	  label: string;
27	  onPress: PressableProps['onPress'];
28	  disabled?: boolean;
29	  loading?: boolean;
30	  style?: StyleProp<ViewStyle>;
31	  accessibilityLabel?: string;
32	  testID?: string;
33	};
34	
35	// Shadow offset + per-axis translate together simulate the neubrutalist
36	// "physical press" — docs/design.md §1.4 (scale 0.97) + §1.5 (shadow (3,3) → (0,0)).
37	// spec uses spring.soft for press feedback; story text said "snappy" but spec wins.
38	function useBaseButton(interactive: boolean) {
39	  const reduced = useReducedMotion();
40	  const pressed = useSharedValue(0);
41	  const spring = withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced);
42	
43	  const animatedStyle = useAnimatedStyle(() => {
44	    const v = pressed.value;
45	    return {
46	      transform: [
47	        { translateX: v * 3 },
48	        { translateY: v * 3 },
49	        { scale: 1 - v * 0.03 },
50	      ],
51	      shadowOffset: { width: 3 - v * 3, height: 3 - v * 3 },
52	    };
53	  });
54	
55	  const handlePressIn = useCallback(() => {
56	    if (!interactive) return;
57	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
58	    pressed.value = withSpring(1, spring);
59	  }, [interactive, pressed, spring]);
60	
61	  const handlePressOut = useCallback(() => {
62	    pressed.value = withSpring(0, spring);
63	  }, [pressed, spring]);
64	
65	  return { animatedStyle, handlePressIn, handlePressOut };
66	}
67	
68	function BaseButton({
69	  label,
70	  onPress,
71	  disabled = false,
72	  loading = false,
73	  variant,
74	  style,
75	  accessibilityLabel,
76	  testID,
77	}: ButtonProps & { variant: Variant }) {
78	  const interactive = !disabled && !loading;
79	  const { animatedStyle, handlePressIn, handlePressOut } = useBaseButton(interactive);
80	
81	  const variantStyle = variant === 'primary' ? styles.primary : styles.secondary;
82	  const labelColor = disabled ? colors.ink40 : colors.ink;
83	  const spinnerColor = variant === 'primary' ? colors.ink : colors.ink;
84	
85	  return (
86	    <Pressable
87	      onPress={interactive ? onPress : undefined}
88	      onPressIn={handlePressIn}
89	      onPressOut={handlePressOut}
90	      disabled={!interactive}
91	      accessibilityRole="button"
92	      accessibilityLabel={accessibilityLabel ?? label}
93	      accessibilityState={{ disabled: !interactive, busy: loading }}
94	      testID={testID}
95	    >
96	      <Animated.View
97	        style={[
98	          styles.base,
99	          variantStyle,
100	          disabled ? styles.disabled : shadows.hard,
101	          animatedStyle,
102	          style,
103	        ]}
104	      >
105	        {loading ? (
106	          <ActivityIndicator color={spinnerColor} />
107	        ) : (
108	          <Text style={[textStyles.body, { color: labelColor }]}>{label}</Text>
109	        )}
110	      </Animated.View>
111	    </Pressable>
112	  );
113	}
114	
115	export function ButtonPrimary(props: ButtonProps) {
116	  return <BaseButton {...props} variant="primary" />;
117	}
118	
119	export function ButtonSecondary(props: ButtonProps) {
120	  return <BaseButton {...props} variant="secondary" />;
121	}
122	
123	const styles = StyleSheet.create({
124	  base: {
125	    minHeight: 48,
126	    paddingHorizontal: spacing.lg,
127	    paddingVertical: spacing.md,
128	    borderRadius: radii.button,
129	    borderWidth: 2,
130	    borderColor: colors.ink,
131	    alignItems: 'center',
132	    justifyContent: 'center',
133	    shadowColor: colors.ink,
134	    shadowOpacity: 1,
135	    shadowRadius: 0,
136	  },
137	  primary: {
138	    backgroundColor: colors.cta,
139	  },
140	  secondary: {
141	    backgroundColor: colors.surface,
142	  },
143	  disabled: {
144	    backgroundColor: colors.hairline,
145	    borderColor: colors.ink40,
146	    shadowOpacity: 0,
147	    elevation: 0,
148	  },
149	});
